import{_ as e,o as t,c as r,ag as i}from"./chunks/framework.BZohXCq9.js";const m=JSON.parse('{"title":"bamdra-openclaw-memory","description":"Full product introduction for bamdra-openclaw-memory, the Bamdra memory system for OpenClaw.","frontmatter":{"title":"bamdra-openclaw-memory","description":"Full product introduction for bamdra-openclaw-memory, the Bamdra memory system for OpenClaw."},"headers":[],"relativePath":"guide/openclaw-topic-memory.md","filePath":"guide/openclaw-topic-memory.md","lastUpdated":null}'),o={name:"guide/openclaw-topic-memory.md"};function l(n,a,c,s,d,u){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="bamdra-openclaw-memory" tabindex="-1">bamdra-openclaw-memory <a class="header-anchor" href="#bamdra-openclaw-memory" aria-label="Permalink to &quot;bamdra-openclaw-memory&quot;">​</a></h1><h2 id="product-summary" tabindex="-1">Product summary <a class="header-anchor" href="#product-summary" aria-label="Permalink to &quot;Product summary&quot;">​</a></h2><p><code>bamdra-openclaw-memory</code> is the main memory plugin in the Bamdra OpenClaw suite. It gives agents a practical memory layer for long-running work: topic-aware continuity, durable fact recall, compact context assembly, and operator-facing control surfaces.</p><p>The simplest way to understand it is as OpenClaw&#39;s context-orchestration layer: it helps the runtime decide what to continue, what to recover, and what to keep available without turning the conversation into a visible memory workflow.</p><p>It can run independently, and its npm-based install flow can also auto-provision <code>bamdra-user-bind</code> so users do not have to run a second install command just to get the identity layer.</p><h2 id="why-it-matters" tabindex="-1">Why it matters <a class="header-anchor" href="#why-it-matters" aria-label="Permalink to &quot;Why it matters&quot;">​</a></h2><p>OpenClaw becomes dramatically more useful when it can keep the right thread alive across interruptions. Without a memory system, teams repeat context, lose stable facts, and waste turns reconstructing what was already decided. <code>bamdra-openclaw-memory</code> is built to solve that operational gap.</p><h2 id="core-capabilities" tabindex="-1">Core capabilities <a class="header-anchor" href="#core-capabilities" aria-label="Permalink to &quot;Core capabilities&quot;">​</a></h2><h3 id="dual-protection-rules-plus-natural-language-guidance" tabindex="-1">Dual protection: rules plus natural-language guidance <a class="header-anchor" href="#dual-protection-rules-plus-natural-language-guidance" aria-label="Permalink to &quot;Dual protection: rules plus natural-language guidance&quot;">​</a></h3><p>The core scheduling model runs on two lines at the same time:</p><ul><li>a rule-backed layer that handles explicit switching, stable facts, safety boundaries, and predictable fallback behavior</li><li>a natural-language layer that makes topic recovery, recall, and switching feel smooth in ordinary conversation</li></ul><p>That combination is what keeps the product both reliable and fluid.</p><h3 id="topic-aware-continuity" tabindex="-1">Topic-aware continuity <a class="header-anchor" href="#topic-aware-continuity" aria-label="Permalink to &quot;Topic-aware continuity&quot;">​</a></h3><p>Separate conversation branches and recover the right one when the user returns to an earlier thread.</p><h3 id="durable-fact-recall" tabindex="-1">Durable fact recall <a class="header-anchor" href="#durable-fact-recall" aria-label="Permalink to &quot;Durable fact recall&quot;">​</a></h3><p>Save preferences, paths, constraints, decisions, and references so the assistant can reuse them later.</p><h3 id="compact-context-assembly" tabindex="-1">Compact context assembly <a class="header-anchor" href="#compact-context-assembly" aria-label="Permalink to &quot;Compact context assembly&quot;">​</a></h3><p>Assemble the active prompt from the branch that matters instead of replaying the entire session.</p><h3 id="explicit-operator-tools" tabindex="-1">Explicit operator tools <a class="header-anchor" href="#explicit-operator-tools" aria-label="Permalink to &quot;Explicit operator tools&quot;">​</a></h3><p>Expose tools for listing topics, switching branches, saving facts, compacting summaries, and searching memory when needed.</p><h2 id="product-value-in-practice" tabindex="-1">Product value in practice <a class="header-anchor" href="#product-value-in-practice" aria-label="Permalink to &quot;Product value in practice&quot;">​</a></h2><ul><li>Better continuity in long OpenClaw sessions</li><li>Less repeated context for the user</li><li>More stable memory for project and environment details</li><li>A clearer route from experimentation to production use</li></ul><h2 id="architecture-at-a-glance" tabindex="-1">Architecture at a glance <a class="header-anchor" href="#architecture-at-a-glance" aria-label="Permalink to &quot;Architecture at a glance&quot;">​</a></h2><ul><li>SQLite is the default system of record</li><li>In-memory cache is the default hot path</li><li>Plugins stay thin and OpenClaw-facing</li><li>Summaries and topic state keep context manageable</li></ul><h2 id="ideal-fit" tabindex="-1">Ideal fit <a class="header-anchor" href="#ideal-fit" aria-label="Permalink to &quot;Ideal fit&quot;">​</a></h2><p>This product is a strong fit when your team:</p><ul><li>uses OpenClaw across long sessions</li><li>revisits earlier topics frequently</li><li>wants reusable fact memory without adding heavy infrastructure</li><li>needs human operators to retain control over memory behavior</li></ul><h2 id="github" tabindex="-1">GitHub <a class="header-anchor" href="#github" aria-label="Permalink to &quot;GitHub&quot;">​</a></h2><ul><li>GitHub home: <a href="https://github.com/bamdra" target="_blank" rel="noreferrer">github.com/bamdra</a></li><li>Repository: <a href="https://github.com/bamdra/bamdra-openclaw-memory" target="_blank" rel="noreferrer">bamdra/bamdra-openclaw-memory</a></li></ul><h2 id="next-reading" tabindex="-1">Next reading <a class="header-anchor" href="#next-reading" aria-label="Permalink to &quot;Next reading&quot;">​</a></h2><ul><li><a href="/guide/installation">Installation</a></li><li><a href="/guide/best-practices">Best Practices</a></li><li><a href="/guide/faq">FAQ</a></li><li><a href="/guide/downloads">Downloads</a></li></ul>',31)])])}const p=e(o,[["render",l]]);export{m as __pageData,p as default};
